mapper.select:
/* ChkLst01Mapper.selectChkptList */ SELECT '' AS CHK , A.CMPNY_CD , A.SITE_CD , B.SITE_NM , A.CHKLST_TYPE , A.CHKPT_CD , A.CHKPT_NM , A.USE_YN , A.CHKPT_DESC , A.MGMT_USER_ID , C.USER_NM AS MGMT_USER_NM FROM TB_CHKPT_TYPE_MGMT A INNER JOIN TB_SITE B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_CD = B.SITE_CD AND B.USE_YN = 'Y' ) LEFT OUTER JOIN TB_USER C ON ( A.CMPNY_CD = C.CMPNY_CD AND A.MGMT_USER_ID = C.USER_ID AND C.USE_YN = 'Y' ) WHERE 1=1 AND A.CMPNY_CD = #{token.gv_cmpnyCd}
AND A.SITE_CD = #{param.sr_siteCd}
AND A.CHKPT_NM LIKE CONCAT('%', #{param.sr_chkptNm}, '%')
AND A.CHKLST_TYPE = #{param.sr_chkLstType}
AND A.USE_YN = #{param.sr_useYn}

mapper.insert:
	/* ChkLst01Mapper.mergeChkptList */	
    INSERT INTO TB_CHKPT_TYPE_MGMT (
    	CMPNY_CD
    	, SITE_CD
    	, CHKLST_TYPE
    	, CHKPT_CD
    	, CHKPT_NM
    	, CHKPT_DESC
    	, MGMT_USER_ID
    	, USE_YN
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, #{param.siteCd}
   		, #{param.chkLstType}
   		, IFNULL(#{param.chkptCd}, prafta.FNC_CMM_SEQ_NEXTVAL(#{token.gv_cmpnyCd}, 'CHKPT_CD'))
   		, #{param.chkptNm}
		, #{param.chkptDesc}
		, #{param.mgmtUserId}
		, #{param.useYn}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    CHKPT_NM    	= VALUES(CHKPT_NM)
	    , CHKPT_DESC 	= VALUES(CHKPT_DESC)
	    , MGMT_USER_ID	= VALUES(MGMT_USER_ID)
	    , USE_YN		= IFNULL(#{param.useYn}, 'Y')
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

/* ChkLst01Mapper.updateChkptList */
UPDATE TB_CHKPT_TYPE_MGMT
SET 
	USE_YN = 'N'
	, UPDATE_NO = #{token.gvuserId}
	, UPDATE_DATE = now()
WHERE 1=1
  AND CMPNY_CD = #{param.cmpnyCd}
  AND SITE_CD = #{param.siteCd}
  AND CHKLST_TYPE = #{param.chkLstType}
  AND CHKPT_CD = #{param.chkptCd}
